SELECT DISTINCT state_name 
FROM states 
WHERE latitude > 30 AND longitude > -120;

SELECT COUNT(*) as facility_count
FROM energy_facilities
WHERE capacity > 100;

SELECT ef.facility_name, ef.capacity
FROM energy_facilities ef
WHERE ef.state_id IN (SELECT state_id FROM incentives);

SELECT state_name, population
FROM states
ORDER BY state_name;
